package com.example.yourapp.api;

import com.example.yourapp.BuildConfig;

import okhttp3.OkHttpClient;
import okhttp3.logging.HttpLoggingInterceptor;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public class RetrofitClient {

    private static Retrofit retrofit = null;

    public static Retrofit getClient() {
        if (retrofit == null) {
            OkHttpClient.Builder httpClient = new OkHttpClient.Builder();

            // Add logging interceptor for development and staging builds
            if (BuildConfig.LOGGING_ENABLED) {
                HttpLoggingInterceptor logging = new HttpLoggingInterceptor();
                logging.setLevel(HttpLoggingInterceptor.Level.BODY); // Log request and response bodies
                httpClient.addInterceptor(logging);
            }

            retrofit = new Retrofit.Builder()
                    .baseUrl(BuildConfig.BASE_URL) // Base URL from BuildConfig
                    .addConverterFactory(GsonConverterFactory.create())
                    .client(httpClient.build())
                    .build();
        }
        return retrofit;
    }

    public static ApiService getApiService() {
        return getClient().create(ApiService.class);
    }
}



// app/src/main/java/com/example/yourapp/MainActivity.java

package com.example.yourapp;

import android.os.Bundle;
import android.util.Log;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.example.yourapp.api.ApiService;
import com.example.yourapp.api.RetrofitClient;
import com.example.yourapp.model.User;

import java.util.List;

import retrofit2.Call;
import retrofit2.Callback;
import retrofit2.Response;

public class MainActivity extends AppCompatActivity {

    private static final String TAG = "MainActivity";
    private TextView resultTextView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        resultTextView = findViewById(R.id.resultTextView);

        // Display current environment's base URL (for verification)
        String envInfo = "Current API Base URL: " + BuildConfig.BASE_URL + "\n";
        envInfo += "Logging Enabled: " + BuildConfig.LOGGING_ENABLED + "\n\n";
        resultTextView.append(envInfo);


        fetchUsers();
    }

    private void fetchUsers() {
        ApiService apiService = RetrofitClient.getApiService();
        Call<List<User>> call = apiService.getUsers();

        call.enqueue(new Callback<List<User>>() {
            @Override
            public void onResponse(Call<List<User>> call, Response<List<User>> response) {
                if (response.isSuccessful() && response.body() != null) {
                    List<User> userList = response.body();
                    StringBuilder userData = new StringBuilder("Fetched Users:\n");
                    for (User user : userList) {
                        userData.append(user.toString()).append("\n");
                    }
                    resultTextView.append(userData.toString());
                    Log.d(TAG, "Users fetched successfully: " + userList.size() + " users.");
                    Toast.makeText(MainActivity.this, "Users fetched!", Toast.LENGTH_SHORT).show();
                } else {
                    String errorBody = "Error: " + response.code() + " " + response.message();
                    try {
                        if (response.errorBody() != null) {
                            errorBody += "\n" + response.errorBody().string();
                        }
                    } catch (Exception e) {
                        Log.e(TAG, "Error parsing error body", e);
                    }
                    resultTextView.append("API Error: " + errorBody);
                    Log.e(TAG, "API Error: " + errorBody);
                    Toast.makeText(MainActivity.this, "Failed to fetch users: " + response.code(), Toast.LENGTH_LONG).show();
                }
            }

            @Override
            public void onFailure(Call<List<User>> call, Throwable t) {
                resultTextView.append("Network Error: " + t.getMessage());
                Log.e(TAG, "Network Error: ", t);
                Toast.makeText(MainActivity.this, "Network error: " + t.getMessage(), Toast.LENGTH_LONG).show();
            }
        });
    }
}



